(function(){
  function qs(s,c){return (c||document).querySelector(s)}
  function qsa(s,c){return Array.from((c||document).querySelectorAll(s))}
  function escHtml(str){return String(str).replace(/[&<>'"]/g,function(m){return({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[m];});}

  document.addEventListener('DOMContentLoaded',function(){
    var body=document.body;
    var topbarInner=qs('.topbar-inner');

    var progressTrack=document.createElement('div');
    progressTrack.className='progress-track';
    progressTrack.innerHTML='<div class="progress-bar" data-read-progress></div>';
    body.appendChild(progressTrack);

    if(topbarInner){
      var controls=document.createElement('div');
      controls.className='topbar-controls';
      controls.innerHTML='<button class="icon-btn" type="button" aria-label="Tema değiştir" data-theme-toggle>◐</button>';
      topbarInner.appendChild(controls);
    }

    var scrollTopBtn=document.createElement('button');
    scrollTopBtn.className='btn btn-secondary scroll-top';
    scrollTopBtn.type='button';
    scrollTopBtn.textContent='↑ Yukarı Çık';
    scrollTopBtn.setAttribute('aria-label','Sayfanın başına dön');
    body.appendChild(scrollTopBtn);

    var themeKey='minifab-theme';
    function setTheme(theme){
      body.classList.toggle('light-theme',theme==='light');
      try{localStorage.setItem(themeKey,theme);}catch(err){}
    }
    try{
      var stored=localStorage.getItem(themeKey);
      if(stored){setTheme(stored);}else if(window.matchMedia&&window.matchMedia('(prefers-color-scheme: light)').matches){setTheme('light');}
    }catch(err){}

    var themeToggle=qs('[data-theme-toggle]');
    if(themeToggle){
      themeToggle.addEventListener('click',function(){
        setTheme(body.classList.contains('light-theme')?'dark':'light');
      });
    }

    function updateScrollUi(){
      var doc=document.documentElement;
      var max=doc.scrollHeight-window.innerHeight;
      var ratio=max>0?(window.scrollY/max)*100:0;
      var bar=qs('[data-read-progress]');
      if(bar){bar.style.width=ratio+'%';}
      scrollTopBtn.classList.toggle('visible',window.scrollY>420);
    }
    window.addEventListener('scroll',updateScrollUi,{passive:true});
    window.addEventListener('resize',updateScrollUi);
    updateScrollUi();

    scrollTopBtn.addEventListener('click',function(){window.scrollTo({top:0,behavior:'smooth'});});

    var toggle=qs('.menu-toggle');
    var nav=qs('nav');
    if(toggle&&nav){
      toggle.addEventListener('click',function(){
        var open=nav.classList.toggle('open');
        toggle.setAttribute('aria-expanded',open?'true':'false');
      });
    }

    var params=new URLSearchParams(window.location.search);
    var sentBanner=qs('[data-sent-banner]');
    if(sentBanner&&params.get('sent')==='1'){sentBanner.hidden=false;}

    var modelName=params.get('model');
    var modelLink=params.get('link');
    var modelNameInput=qs('#modelAdi');
    var modelLinkInput=qs('#modelLink');
    var prefillBanner=qs('[data-prefill-banner]');
    if(modelName&&modelNameInput){modelNameInput.value=modelName;}
    if(modelLink&&modelLinkInput){modelLinkInput.value=modelLink;}
    if(prefillBanner&&(modelName||modelLink)){prefillBanner.hidden=false;}

    qsa('.qty-btn').forEach(function(btn){
      btn.addEventListener('click',function(){
        var input=qs('#adet');
        if(!input)return;
        var val=parseInt(input.value||'1',10);
        if(btn.dataset.qty==='plus'){input.value=val+1;}
        else{input.value=Math.max(1,val-1);}    
      });
    });

    qsa('form[data-formsubmit]').forEach(function(form){
      form.addEventListener('submit',function(e){
        var honey=qs('input[name="_honey"]',form);
        if(honey&&honey.value.trim()!==''){e.preventDefault();return;}

        var required=[
          {id:'adSoyad',msg:'Lütfen ad soyad girin.'},
          {id:'email',msg:'Lütfen e-posta adresi girin.'},
          {id:'modelLink',msg:'Lütfen model linkini girin.'},
          {id:'adet',msg:'Lütfen adet girin.'}
        ];

        for(var i=0;i<required.length;i++){
          var field=qs('#'+required[i].id,form);
          if(field&&!field.value.trim()){
            e.preventDefault();
            field.setCustomValidity(required[i].msg);
            field.reportValidity();
            return;
          }
          if(field){field.setCustomValidity('');}
        }

        var email=qs('#email',form);
        if(email&&!email.value.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)){
          e.preventDefault();
          email.setCustomValidity('Lütfen geçerli bir e-posta adresi girin.');
          email.reportValidity();
          return;
        }
        if(email){email.setCustomValidity('');}

        if(!form.checkValidity()){
          e.preventDefault();
          form.reportValidity();
        }
      });
    });

    var quoteForm=qs('.quote-form');
    if(quoteForm){
      var estimateOutput=qs('[data-estimator-output]',quoteForm);
      var quantityField=qs('#quantity',quoteForm);
      var materialField=qs('#material',quoteForm);
      var serviceField=qs('#serviceType',quoteForm);
      var urgencyField=qs('#urgency',quoteForm);

      function updateEstimate(){
        if(!estimateOutput)return;
        var qty=Math.max(parseInt(quantityField&&quantityField.value||'1',10),1);
        var material=((materialField&&materialField.value)||'PLA').toUpperCase();
        var materialFactor={PLA:1,PETG:1.2,ABS:1.3,TPU:1.4,'BILMIYORUM':1.15}[material]||1;
        var service=((serviceField&&serviceField.value)||'3D Baskı');
        var serviceFactor=service.indexOf('Tasarım')>-1?1.45:service.indexOf('Kurumsal')>-1?1.6:1;
        var rushFactor=urgencyField&&urgencyField.value==='rush'?1.3:1;
        var low=Math.max(350,Math.round(220*qty*materialFactor*serviceFactor*rushFactor));
        var high=Math.round(low*1.35);
        estimateOutput.textContent='₺'+low.toLocaleString('tr-TR')+' - ₺'+high.toLocaleString('tr-TR');
      }
      [quantityField,materialField,serviceField,urgencyField].forEach(function(field){if(field){field.addEventListener('input',updateEstimate);field.addEventListener('change',updateEstimate);}});
      updateEstimate();

      var autoKey=quoteForm.getAttribute('data-autosave');
      if(autoKey){
        var fields=qsa('input,select,textarea',quoteForm).filter(function(el){return el.name&&!el.type.match(/file|submit|hidden|checkbox|radio/);});
        try{
          var saved=localStorage.getItem(autoKey);
          if(saved){
            var data=JSON.parse(saved);
            fields.forEach(function(el){if(data[el.name]){el.value=data[el.name];}});
          }
        }catch(err){}
        fields.forEach(function(el){
          el.addEventListener('input',function(){
            try{
              var payload={};
              fields.forEach(function(field){payload[field.name]=field.value;});
              localStorage.setItem(autoKey,JSON.stringify(payload));
            }catch(err){}
          });
        });
        quoteForm.addEventListener('submit',function(){try{localStorage.removeItem(autoKey);}catch(err){}});
      }

      quoteForm.addEventListener('submit',function(e){
        var linkField=qs('#modelLink',quoteForm);
        var fileField=qs('#modelFile',quoteForm);
        var hasLink=!!(linkField&&linkField.value.trim());
        var hasFile=!!(fileField&&fileField.files&&fileField.files.length>0);

        if(linkField){linkField.setCustomValidity('');}
        if(fileField){fileField.setCustomValidity('');}

        if(!hasLink&&!hasFile){
          e.preventDefault();
          if(linkField){
            linkField.setCustomValidity('Lütfen model linki ekleyin veya STL dosyası yükleyin.');
            linkField.reportValidity();
          }
          return;
        }

        if(fileField&&fileField.files&&fileField.files.length>0){
          var file=fileField.files[0];
          var validExt=/\.(stl|3mf|obj)$/i.test(file.name);
          if(!validExt){
            e.preventDefault();
            fileField.setCustomValidity('Lütfen STL, 3MF veya OBJ formatında dosya yükleyin.');
            fileField.reportValidity();
            return;
          }
        }
      });
    }

    var products=window.MINIFAB_PRODUCTS||null;
    var productsGrid=qs('#products-grid');
    if(products&&productsGrid){
      productsGrid.innerHTML=products.map(function(p){
        var teklif='teklif.html?model='+encodeURIComponent(p.title)+'&link='+encodeURIComponent(p.link);
        return '<article class="card product-card generated-card" data-category="'+escHtml(p.category)+'">'+
          (p.popular?'<span class="pop-badge">Popüler</span>':'')+
          '<a class="card-main-link" href="'+escHtml(p.link)+'" target="_blank" rel="noopener noreferrer">'+
          '<img class="topic-thumb" src="'+escHtml(p.img)+'" width="700" height="420" loading="lazy" decoding="async" alt="'+escHtml(p.title)+' 3D baskı örneği" />'+
          '<h2>'+escHtml(p.title)+'</h2></a>'+
          '<p>'+escHtml(p.description)+'</p>'+
          '<div class="meta-row"><span class="tag">'+escHtml(p.material)+'</span><span class="tag">'+escHtml(p.time)+'</span><span class="tag">'+escHtml(p.category)+'</span></div>'+
          '<a class="btn btn-secondary" href="'+escHtml(p.link)+'" target="_blank" rel="noopener noreferrer">MakerWorld\'de aç</a>'+
          '<a class="btn btn-primary" href="'+teklif+'">Bunu Bastır (Teklif Al)</a>'+
          '</article>';
      }).join('');

      qsa('.generated-card').forEach(function(card){
        card.addEventListener('click',function(e){
          if(e.target.closest('a')||e.target.closest('button')) return;
          var main=qs('.card-main-link',card);
          if(main){window.open(main.href,'_blank','noopener');}
        });
      });
    }

    function applyCardFilters(){
      var activeBtn=qs('.filter-btn.active');
      var key=activeBtn?activeBtn.getAttribute('data-filter'):'all';
      qsa('[data-live-search]').forEach(function(input){
        var target=input.getAttribute('data-live-search');
        var term=(input.value||'').trim().toLowerCase();
        var visible=0;
        qsa(target).forEach(function(card){
          var cat=card.getAttribute('data-category');
          var categoryMatch=(key==='all'||cat===key);
          var text=(card.textContent||'').toLowerCase();
          var searchMatch=!term||text.indexOf(term)>-1;
          var show=categoryMatch&&searchMatch;
          card.style.display=show?'block':'none';
          if(show){visible++;}
        });
        var counter=qs('[data-results-count="'+target+'"]');
        if(counter){counter.textContent=visible+' sonuç listeleniyor.';}
      });

      if(!qsa('[data-live-search]').length){
        qsa('.product-card,.blog-card').forEach(function(card){
          var cat=card.getAttribute('data-category');
          card.style.display=(key==='all'||cat===key)?'block':'none';
        });
      }
    }

    var filterButtons=qsa('.filter-btn');
    if(filterButtons.length){
      filterButtons.forEach(function(btn){
        btn.addEventListener('click',function(){
          filterButtons.forEach(function(x){x.classList.remove('active')});
          btn.classList.add('active');
          applyCardFilters();
        });
      });
    }

    qsa('[data-live-search]').forEach(function(input){
      input.addEventListener('input',applyCardFilters);
    });
    applyCardFilters();

    if(document.body.dataset.redirectHome==='true'){
      setTimeout(function(){window.location.href='index.html';},2000);
    }
  });
})();
